@app.route('/admin/tokens/issue', methods=['POST'])
@require_oauth('admin')
def issue_token():
    """
    Issue a new access token for a client.
    This is an admin endpoint for the API gateway to issue tokens.
    """
    data = request.get_json()
    if not data:
        return jsonify({'error': 'bad_request'}), 400

    client_id = data.get('client_id')
    user_id = data.get('user_id')
    scopes = data.get('scopes', [])
    ttl_seconds = data.get('ttl_seconds', 3600)

    # Validate TTL bounds
    if ttl_seconds < 60 or ttl_seconds > 86400:
        return jsonify({
            'error': 'bad_request',
            'error_description': 'ttl_seconds must be between 60 and 86400.'
        }), 400

    client = OAuthClient.query.get(client_id)
    if not client or not client.is_active:
        return jsonify({'error': 'invalid_client'}), 400

    # Validate requested scopes against client's allowed scopes
    allowed = client.get_allowed_scopes()
    requested = set(scopes)
    if not requested.issubset(allowed):
        disallowed = requested - allowed
        return jsonify({
            'error': 'invalid_scope',
            'error_description': f'Client is not allowed scopes: {", ".join(disallowed)}'
        }), 400

    # Generate token
    raw_token = secrets.token_urlsafe(48)
    token_hash = AccessToken.hash_token(raw_token)

    now = datetime.now(timezone.utc)
    token_record = AccessToken(
        token_hash=token_hash,
        client_id=client_id,
        user_id=user_id,
        scopes=' '.join(sorted(scopes)),
        issued_at=now,
        expires_at=now + timedelta(seconds=ttl_seconds),
        revoked=False
    )
    db.session.add(token_record)
    db.session.commit()

    return jsonify({
        'access_token': raw_token,
        'token_type': 'Bearer',
        'expires_in': ttl_seconds,
        'scopes': scopes
    }), 201


@app.route('/admin/tokens/revoke', methods=['POST'])
@require_oauth('admin')
def revoke_token():
    """Revoke an access token."""
    data = request.get_json()
    if not data or 'token' not in data:
        return jsonify({'error': 'bad_request'}), 400

    raw_token = data['token']
    token_hash = AccessToken.hash_token(raw_token)
    token_record = AccessToken.query.filter_by(token_hash=token_hash).first()

    if token_record is None:
        # Per RFC 7009, revoking an invalid token should still return 200
        return jsonify({'revoked': True})

    token_record.revoked = True
    db.session.commit()

    return jsonify({'revoked': True})


@app.route('/admin/clients', methods=['POST'])
@require_oauth('admin')
def register_client():
    """Register a new OAuth client."""
    data = request.get_json()
    if not data or 'client_name' not in data:
        return jsonify({'error': 'bad_request'}), 400

    client_id = secrets.token_hex(16)
    client_secret = secrets.token_urlsafe(48)
    allowed_scopes = data.get('allowed_scopes', [])

    client = OAuthClient(
        id=client_id,
        client_name=data['client_name'],
        allowed_scopes=' '.join(allowed_scopes),
        is_active=True
    )
    client.set_client_secret(client_secret)

    db.session.add(client)
    db.session.commit()

    return jsonify({
        'client_id': client_id,
        'client_secret': client_secret,
        'client_name': data['client_name'],
        'allowed_scopes': allowed_scopes
    }), 201


